import { useState, useRef, useEffect } from 'react';
import { sendChatMessage, getContactInfo } from '../services/chatbotService';

const Chatbot = ({ isOpen, onClose }) => {
  const [messages, setMessages] = useState([
    {
      role: 'assistant',
      content: 'Hello! I\'m your MCT assistant. I\'m here to help you learn about the Ease Band and how it can provide relief from menstrual cramps. How can I assist you today?',
      timestamp: new Date()
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(true);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  const handleSendMessage = async (e) => {
    e.preventDefault();

    if (!inputMessage.trim() || isLoading) return;

    const userMessage = {
      role: 'user',
      content: inputMessage.trim(),
      timestamp: new Date()
    };

    setMessages((prev) => [...prev, userMessage]);
    setInputMessage('');
    setIsLoading(true);
    setShowSuggestions(false);

    try {
      const apiMessages = [...messages, userMessage].map(({ role, content }) => ({
        role,
        content
      }));

      const response = await sendChatMessage(apiMessages);

      const assistantMessage = {
        role: 'assistant',
        content: response.message,
        timestamp: new Date()
      };

      setMessages((prev) => [...prev, assistantMessage]);
      setShowSuggestions(true);
    } catch (error) {
      const contactInfo = getContactInfo();
      const errorMessage = {
        role: 'assistant',
        content: `Sorry, I encountered an error. Please contact our support team at ${contactInfo.email} for assistance.`,
        timestamp: new Date()
      };
      setMessages((prev) => [...prev, errorMessage]);
      setShowSuggestions(false);
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickQuestion = (question) => {
    setInputMessage(question);
    inputRef.current?.focus();
  };

  const initialQuestions = [
    'How does Ease Band relieve period cramps?',
    'What are the key features?',
    'How long does the battery last?'
  ];

  const suggestedQuestions = [
    'Is it safe to use daily?',
    'How do I clean the Ease Band?',
    'What is the warranty?',
    'How much does it cost?',
    'Can I wear it while sleeping?',
    'Is it waterproof?'
  ];

  // Get random 3 suggested questions
  const getRandomSuggestions = () => {
    const shuffled = [...suggestedQuestions].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, 3);
  };

  const [currentSuggestions, setCurrentSuggestions] = useState(getRandomSuggestions());

  useEffect(() => {
    if (showSuggestions && messages.length > 1) {
      setCurrentSuggestions(getRandomSuggestions());
    }
  }, [showSuggestions, messages.length]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-end p-6">
      <div className="w-full max-w-md h-[600px] bg-white border-2 border-blue-500 flex flex-col shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b-2 border-blue-100 bg-gradient-to-r from-blue-50 to-white">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-blue-500 flex items-center justify-center">
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 text-white">
                <path d="M20 6h-4V4c0-1.1-.9-2-2-2h-4c-1.1 0-2 .9-2 2v2H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2zM10 4h4v2h-4V4zm2 14c-2.21 0-4-1.79-4-4s1.79-4 4-4 4 1.79 4 4-1.79 4-4 4zm0-6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2z" />
              </svg>
            </div>
            <div>
              <h3 className="text-gray-900 font-medium text-lg tracking-wide">Medical Assistant</h3>
              <span className="text-blue-600 text-xs font-medium tracking-wider uppercase flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-pulse"></span>
                Available 24/7
              </span>
            </div>
          </div>
          <button
            onClick={onClose}
            aria-label="Close chat"
            className="text-gray-500 hover:text-gray-900 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="w-5 h-5">
              <line x1="18" y1="6" x2="6" y2="18"></line>
              <line x1="6" y1="6" x2="18" y2="18"></line>
            </svg>
          </button>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-gray-50">
          {messages.map((message, index) => (
            <div key={index}>
              <div
                className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[80%] ${message.role === 'user' ? 'order-2' : 'order-1'}`}>
                  <div
                    className={`px-4 py-3 ${message.role === 'user'
                        ? 'bg-blue-500'
                        : 'bg-white border-2 border-blue-100'
                      }`}
                  >
                    <p className={`text-sm font-light leading-relaxed ${message.role === 'user' ? 'text-white' : 'text-gray-800'}`}>{message.content}</p>
                  </div>
                  <div className="text-xs text-gray-500 mt-1 px-1 font-light">
                    {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>

              {/* Show suggestions after assistant messages */}
              {message.role === 'assistant' && index === messages.length - 1 && showSuggestions && messages.length > 1 && (
                <div className="mt-3 space-y-2">
                  <p className="text-xs text-gray-500 font-medium uppercase tracking-wider">You might also ask:</p>
                  {currentSuggestions.map((question, qIndex) => (
                    <button
                      key={qIndex}
                      onClick={() => handleQuickQuestion(question)}
                      className="w-full text-left px-3 py-2 text-xs text-gray-700 bg-white border border-blue-200 hover:border-blue-500 hover:bg-blue-50 transition-all font-light rounded"
                    >
                      {question}
                    </button>
                  ))}
                </div>
              )}
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white border-2 border-blue-100 px-4 py-3">
                <div className="flex gap-1">
                  <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></span>
                  <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></span>
                  <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></span>
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Initial Quick Questions */}
        {messages.length === 1 && (
          <div className="px-6 py-4 border-t-2 border-blue-100 bg-white">
            <p className="text-gray-600 text-xs uppercase tracking-wider mb-3 font-medium">Quick questions:</p>
            <div className="space-y-2">
              {initialQuestions.map((question, index) => (
                <button
                  key={index}
                  onClick={() => handleQuickQuestion(question)}
                  className="w-full text-left px-4 py-2 text-sm text-gray-700 border-2 border-blue-200 hover:border-blue-500 hover:bg-blue-50 transition-all font-light"
                >
                  {question}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Input */}
        <form onSubmit={handleSendMessage} className="p-6 border-t-2 border-blue-100 bg-white">
          <div className="flex gap-3">
            <input
              ref={inputRef}
              type="text"
              value={inputMessage}
              onChange={(e) => setInputMessage(e.target.value)}
              placeholder="Type your message..."
              className="flex-1 px-4 py-3 bg-gray-50 border-2 border-blue-200 text-gray-900 placeholder-gray-500 focus:outline-none focus:border-blue-500 transition-colors font-light text-sm"
              disabled={isLoading}
            />
            <button
              type="submit"
              className="px-4 py-3 bg-blue-500 text-white hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
              disabled={!inputMessage.trim() || isLoading}
              aria-label="Send message"
            >
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="w-5 h-5">
                <line x1="22" y1="2" x2="11" y2="13"></line>
                <polygon points="22 2 15 22 11 13 2 9 22 2"></polygon>
              </svg>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Chatbot;

import React from 'react';
import { motion } from 'framer-motion';
import { Thermometer, Waves, EyeOff, Battery, Feather, Shield } from 'lucide-react';

const features = [
    {
        icon: <Thermometer className="w-8 h-8" />,
        title: 'INSTANT HEAT',
    },
    {
        icon: <Waves className="w-8 h-8" />,
        title: 'GENTLE MASSAGE',
    },
    {
        icon: <EyeOff className="w-8 h-8" />,
        title: 'DISCREET DESIGN',
    },
    {
        icon: <Battery className="w-8 h-8" />,
        title: 'ALL-DAY BATTERY',
    },
    {
        icon: <Feather className="w-8 h-8" />,
        title: 'LIGHTWEIGHT',
    },
    {
        icon: <Shield className="w-8 h-8" />,
        title: 'SKIN-SAFE',
    },
];

const Features = () => {
    return (
        <section id="features" className="py-24 bg-white relative">
            {/* Technical Grid Background */}
            <div className="absolute inset-0 pointer-events-none opacity-[0.08]"
                style={{
                    backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)',
                    backgroundSize: '40px 40px',
                    maskImage: 'linear-gradient(to bottom, transparent, black 20%, black 80%, transparent)',
                    WebkitMaskImage: 'linear-gradient(to bottom, transparent, black 20%, black 80%, transparent)'
                }}
            />

            <div className="container mx-auto px-6 relative z-10">
                <div className="text-center mb-16">
                    <motion.h2
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.6 }}
                        className="text-4xl md:text-6xl font-bold text-black mb-4 font-orbitron tracking-wider"
                    >
                        FEATURES
                    </motion.h2>
                    <div className="h-1 w-24 bg-black mx-auto mt-4"></div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-0 border-t border-l border-gray-200">
                    {features.map((feature, index) => (
                        <motion.div
                            key={index}
                            initial={{ opacity: 0 }}
                            whileInView={{ opacity: 1 }}
                            viewport={{ once: true }}
                            transition={{ duration: 0.5, delay: index * 0.05 }}
                            className="relative p-8 border-b border-r border-gray-200 bg-white/60 backdrop-blur-sm group flex flex-col items-center justify-center aspect-square"
                        >
                            {/* Corner Accents */}
                            <div className="absolute top-0 left-0 w-2 h-2 border-t-2 border-l-2 border-black opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                            <div className="absolute top-0 right-0 w-2 h-2 border-t-2 border-r-2 border-black opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                            <div className="absolute bottom-0 left-0 w-2 h-2 border-b-2 border-l-2 border-black opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                            <div className="absolute bottom-0 right-0 w-2 h-2 border-b-2 border-r-2 border-black opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

                            <div className="mb-4 text-black group-hover:scale-110 transition-transform duration-300">
                                {feature.icon}
                            </div>

                            <h3 className="text-xl font-bold text-black font-orbitron tracking-widest text-center">
                                {feature.title}
                            </h3>
                        </motion.div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default Features;

import React, { useState, useEffect } from 'react';
import { motion, useScroll, useTransform } from 'framer-motion';

const Hero = () => {
    const [scrollY, setScrollY] = useState(0);
    const { scrollYProgress } = useScroll();

    useEffect(() => {
        const handleScroll = () => {
            setScrollY(window.scrollY);
        };

        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const opacity = useTransform(scrollYProgress, [0, 0.3], [1, 0]);
    const scale = useTransform(scrollYProgress, [0, 0.3], [1.2, 1]);

    return (
        <section id="home" className="relative h-screen flex items-center justify-center overflow-hidden">
            {/* Background Image with Parallax */}
            <motion.div
                className="absolute inset-0 z-0"
                style={{ scale }}
            >
                <div className="absolute inset-0 bg-black/30 z-10" />
                <div
                    className="w-full h-full bg-cover bg-center"
                    style={{
                        backgroundImage: `url("https://res.cloudinary.com/dkganhypn/image/upload/v1766937813/ChatGPT_Image_Dec_28_2025_09_32_44_PM_mard9h.png")`,
                        transform: `translateY(${scrollY * 0.3}px)`
                    }}
                />
            </motion.div>

            {/* Product-First Hero Content */}
            <div className="container mx-auto px-6 relative z-20 text-center">
                <motion.div
                    style={{ opacity }}
                    className="space-y-8"
                >
                    {/* Hero Product Name - The Star */}
                    <motion.h1
                        initial={{ opacity: 0, y: 50 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 1.2, delay: 0.3, ease: [0.6, 0.05, 0.01, 0.9] }}
                        className="text-7xl md:text-[10rem] font-light text-white tracking-[0.15em] leading-none"
                    >
                        Ease Band
                    </motion.h1>

                    {/* Impactful Product Quote */}
                    <motion.p
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 1, delay: 0.8 }}
                        className="text-xl md:text-2xl text-white/90 font-light italic max-w-3xl mx-auto leading-relaxed"
                    >
                        A wearable relief band designed to ease menstrual cramps
                    </motion.p>

                    {/* Divider Line */}
                    <motion.div
                        initial={{ scaleX: 0 }}
                        animate={{ scaleX: 1 }}
                        transition={{ duration: 1, delay: 1 }}
                        className="h-px bg-white/30 max-w-sm mx-auto"
                    />

                    {/* Product Description */}
                    <motion.p
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ duration: 1, delay: 1.2 }}
                        className="text-base md:text-lg text-gray-300 font-light max-w-2xl mx-auto leading-relaxed"
                    >
                        "Relief that moves with you. Freedom that stays with you."
                    </motion.p>

                    {/* CTA Buttons */}
                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 1, delay: 1.4 }}
                        className="flex flex-col sm:flex-row gap-6 justify-center items-center pt-6"
                    >
                        <a
                            href="#product-showcase"
                            className="group relative px-12 py-4 bg-white text-black font-medium uppercase tracking-[0.2em] text-sm overflow-hidden transition-all duration-500 hover:tracking-[0.3em]"
                        >
                            <span className="relative z-10">Learn More</span>
                            <div className="absolute inset-0 bg-black transform scale-x-0 group-hover:scale-x-100 transition-transform duration-500 origin-left" />
                            <span className="absolute inset-0 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-opacity duration-500 tracking-[0.3em]">
                                Learn More
                            </span>
                        </a>
                        <a
                            href="/contact"
                            className="px-12 py-4 border border-white text-white font-medium uppercase tracking-[0.2em] text-sm hover:bg-white hover:text-black transition-all duration-500 hover:tracking-[0.3em]"
                        >
                            Contact
                        </a>
                    </motion.div>

                    {/* Company Signature - Subtle Brand Placement */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ duration: 1, delay: 1.8 }}
                        className="pt-8"
                    >
                        <p className="text-sm text-white/50 tracking-[0.3em] uppercase font-light">
                            by
                        </p>
                        <p className="text-lg md:text-xl text-white/70 tracking-[0.4em] font-light mt-1 font-serif">
                            MCT
                        </p>
                    </motion.div>
                </motion.div>
            </div>


        </section>
    );
};

export default Hero;

import React, { useRef } from 'react';
import { motion, useScroll, useTransform } from 'framer-motion';

const LifestyleUsage = () => {
    const containerRef = useRef(null);
    const { scrollYProgress } = useScroll({
        target: containerRef,
        offset: ["start start", "end end"]
    });

    const backgroundColor = useTransform(
        scrollYProgress,
        [0, 0.33, 0.66, 1],
        ["#0a0a0a", "#111827", "#1e293b", "#eff6ff"]
    );

    const useCases = [
        {
            title: "Work",
            subtitle: "Uninterrupted Focus",
            description: "Discreet support during long hours, meetings, and daily tasks. Designed to remain invisible, giving you the confidence to lead without distraction.",
            image: "https://res.cloudinary.com/dkganhypn/image/upload/v1767017722/ChatGPT_Image_Dec_29_2025_07_44_59_PM_qw5e8q.png",
            label: "Discretion & Confidence"
        },
        {
            title: "Travel",
            subtitle: "Movement Without Limits",
            description: "Comfort that moves with you ΓÇö wherever the day takes you. From long flights to city walks, Ease Band ensures your plans stay on track.",
            image: "https://images.unsplash.com/photo-1503221043305-f7498f8b7888?auto=format&fit=crop&q=80&w=2000",
            label: "Freedom of Movement"
        },
        {
            title: "Rest",
            subtitle: "Quiet Restoration",
            description: "Gentle relief when your body needs stillness. A soft companion for those moments of decompression, providing warmth without overstimulation.",
            image: "https://images.unsplash.com/photo-1540555700478-4be289fbecef?auto=format&fit=crop&q=80&w=2000",
            label: "Gentleness & Calm"
        },
        {
            title: "Daily Wear",
            subtitle: "Seamless Integration",
            description: "Designed to blend effortlessly into everyday life. No need to plan your outfit or routine around your relief ΓÇö it simply fits.",
            image: "https://res.cloudinary.com/dkganhypn/image/upload/v1767017654/ChatGPT_Image_Dec_29_2025_07_42_39_PM_asw22l.png",
            label: "Natural Ease"
        }
    ];

    return (
        <section ref={containerRef} className="relative">
            {/* Dynamic Background Layer */}
            <motion.div
                style={{ backgroundColor }}
                className="absolute inset-0 z-0 h-full w-full"
            />

            {/* Content Container */}
            <div className="relative z-10 pb-24">
                {/* Header */}
                <div className="pt-32 pb-24 text-center container mx-auto px-6">
                    <motion.div
                        initial={{ opacity: 0, scaleX: 0 }}
                        whileInView={{ opacity: 1, scaleX: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 1 }}
                        className="h-px w-24 bg-white/30 mx-auto mb-12"
                    />
                    <motion.h2
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8 }}
                        className="text-4xl md:text-5xl lg:text-6xl font-light mb-6 font-serif text-white"
                    >
                        Designed for Real Life
                    </motion.h2>
                    <motion.p
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8, delay: 0.2 }}
                        className="text-gray-400 text-xs md:text-sm font-light tracking-[0.3em] uppercase"
                    >
                        Ease Band adapts to your routine
                    </motion.p>
                </div>

                {/* Vertical Scroll Sections */}
                <div className="flex flex-col gap-24 md:gap-32 px-4 md:px-8">
                    {useCases.map((item, index) => (
                        <motion.div
                            key={index}
                            className="relative w-full max-w-6xl mx-auto h-[60vh] md:h-[75vh] rounded-2xl md:rounded-[2.5rem] overflow-hidden group shadow-2xl"
                            initial={{ opacity: 0, y: 50, scale: 0.95 }}
                            whileInView={{ opacity: 1, y: 0, scale: 1 }}
                            viewport={{ once: true, margin: "-10%" }}
                            transition={{ duration: 0.8 }}
                        >
                            {/* Background Image */}
                            <img
                                src={item.image}
                                alt={item.title}
                                className="absolute inset-0 w-full h-full object-cover transition-transform duration-[2s] group-hover:scale-105"
                            />

                            {/* Gradient Overlay for Text Readability */}
                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />
                            <div className="absolute inset-0 bg-black/20" /> {/* General dimming */}

                            {/* Centered Content Overlay */}
                            <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-6 md:p-12 text-white">
                                <motion.div
                                    initial={{ opacity: 0, y: 20 }}
                                    whileInView={{ opacity: 1, y: 0 }}
                                    viewport={{ once: true }}
                                    transition={{ duration: 0.8, delay: 0.2 }}
                                    className="max-w-3xl"
                                >
                                    <p className="text-xs md:text-sm tracking-[0.3em] uppercase mb-6 md:mb-8 text-white/70">
                                        {item.label}
                                    </p>
                                    <h3 className="text-4xl md:text-6xl lg:text-7xl font-light mb-8 font-serif italic drop-shadow-lg">
                                        {item.title}
                                    </h3>
                                    <div className="h-px w-24 bg-white/40 mx-auto mb-8" />
                                    <p className="text-lg md:text-2xl leading-relaxed font-light text-gray-200 drop-shadow-md">
                                        {item.description}
                                    </p>
                                </motion.div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default LifestyleUsage;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = ({ useDarkText = false }) => {
    const [isScrolled, setIsScrolled] = useState(false);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const location = useLocation();
    const isHomePage = location.pathname === '/';
    const isShopPage = location.pathname === '/shop';
    const isContactPage = location.pathname === '/contact';
    const isTeamPage = location.pathname === '/team';
    const isComingSoonPage = location.pathname === '/coming-soon';

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 100);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    // Dynamic classes based on scroll and theme
    const textColorClass = isScrolled || !useDarkText ? "text-white" : "text-black";
    const borderColorClass = isScrolled || !useDarkText ? "border-white" : "border-black";

    return (
        <motion.nav
            className={`fixed top-0 left-0 right-0 z-50 transition-all duration-700 ${isScrolled
                ? 'bg-black/95 backdrop-blur-xl py-4'
                : 'bg-transparent py-8'
                }`}
        >
